// Shared variables for two processes
boolean flag[2] = {false, false};
int turn;

// Code for Process i (where i is 0 or 1, j is other)
do {
    // Entry Section
    flag[i] = true;           // Process i wants to enter
    turn = j;                 // Give priority to other process
    while (flag[j] && turn == j);  // Wait while other wants CS and it's j's turn

    // Critical Section
    critical_section();

    // Exit Section
    flag[i] = false;          // Process i done with CS

    // Remainder Section
    remainder_section();
} while (true);

// Global lock variable
boolean lock = false;

// Test-and-Set function (atomic hardware instruction)
boolean test_and_set(boolean *target) {
    boolean temp = *target;   // Save old value
    *target = true;          // Set to true atomically
    return temp;             // Return old value
}

// Process entering critical section
do {
    // Entry section with spinlock
    while (test_and_set(&lock));  // Wait until lock was false

    // Critical Section
    critical_section();

    // Exit section
    lock = false;            // Release lock

    // Remainder Section
    remainder_section();
} while (true);

// Semaphore structure
typedef struct {
    int value;
    Queue waiting_queue;
} Semaphore;

// Initialize semaphore to 1 for mutual exclusion
Semaphore mutex;
mutex.value = 1;

// Wait operation (P operation)
void wait(Semaphore *S) {
    S->value--;
    if (S->value < 0) {
        // Block this process
        block_current_process();
        add_to_queue(S->waiting_queue);
    }
}

// Signal operation (V operation)
void signal(Semaphore *S) {
    S->value++;
    if (S->value <= 0) {
        // Wake up a waiting process
        Process *p = remove_from_queue(S->waiting_queue);
        wake_up_process(p);
    }
}

// Process using semaphore for CS
do {
    wait(&mutex);           // Enter CS (decrement)

    critical_section();     // Access shared resource

    signal(&mutex);         // Exit CS (increment)

    remainder_section();
} while (true);

// Monitor definition (pseudocode)
monitor SharedCounter {
    private:
        int count = 0;
        condition not_full, not_empty;

    public:
        // Only one process can execute any procedure at a time

        procedure increment() {
            while (count == MAX)      // Condition wait
                not_full.wait();
            count++;
            not_empty.signal();
        }

        procedure decrement() {
            while (count == 0)        // Condition wait
                not_empty.wait();
            count--;
            not_full.signal();
        }

        function getCount() returns int {
            return count;
        }
}

// Using the monitor
process Producer {
    SharedCounter.increment();
}

process Consumer {
    SharedCounter.decrement();
}
